1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	
22	type Scenario = {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Array<{ op: "quote"; items: Item[] }>;
25	};
26	
27	type QuoteResult = { premium: number };
28	
29	const COMPONENT_BLOCK_SIZE = 3;
30	const COMPONENT_BLOCK_PREMIUM = 60;
31	
32	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
33	
34	const sumOfBasePremiums = (items: Item[]): number =>
35	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
36	
37	const groupByType = (items: Item[]): Item[][] => {
38	  const groups = items.reduce<Record<string, Item[]>>((acc, item) => {
39	    (acc[item.type] ??= []).push(item);
40	    return acc;
41	  }, {});
42	  return Object.values(groups);
43	};
44	
45	const basePremiumForGroup = (group: Item[]): number =>
46	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
47	
48	const basePremiumFor = (items: Item[]): number =>
49	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
50	
51	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
52	
53	const SURCHARGE_RULES: SurchargeRule[] = [
54	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
55	  {
56	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
57	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
58	  },
59	];
60	
61	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
62	  items.reduce(
63	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
64	    0,
65	  );
66	
67	const surchargesFor = (items: Item[]): number =>
68	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
69	
70	type Customer = { yearsWithMHPCO: number };
71	type PolicyContext = { customer: Customer; isFollowUp: boolean };
72	
73	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
74	
75	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
76	  {
77	    rate: LOYALTY_DISCOUNT_RATE,
78	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
79	  },
80	  {
81	    rate: FOLLOW_UP_DISCOUNT_RATE,
82	    applies: ({ isFollowUp }) => isFollowUp,
83	  },
84	];
85	
86	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
87	  POLICY_DISCOUNT_RULES.reduce(
88	    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
89	    0,
90	  );
91	
92	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
93	  const base = basePremiumFor(items);
94	  const surcharges = surchargesFor(items);
95	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
96	  return {
97	    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
98	  };
99	};
100	
101	export const processScenario = ({ customer, steps }: Scenario): { results: QuoteResult[] } => ({
102	  results: steps.map((step, index) => quotePremium(step.items, customer, index > 0)),
103	});
